#include <stdio.h>
#include <stdlib.h>

typedef struct Edge {int to; int id; struct Edge *next;} Edge;

int main(){int T; if(scanf("%d",&T)!=1) return 0; while(T--){int N,M; scanf("%d %d",&N,&M);
 int totalV = 2*N+5; // rows 1..N, columns N+1..2N
 Edge **adj = (Edge**)calloc(totalV,sizeof(Edge*));
 int *r = (int*)malloc((M+1)*sizeof(int));
 int *c = (int*)malloc((M+1)*sizeof(int));
 for(int i=1;i<=M;i++){
   scanf("%d %d",&r[i],&c[i]);
   int u = r[i];
   int v = N + c[i];
   Edge *e1 = (Edge*)malloc(sizeof(Edge)); e1->to=v; e1->id=i; e1->next=adj[u]; adj[u]=e1;
   Edge *e2 = (Edge*)malloc(sizeof(Edge)); e2->to=u; e2->id=i; e2->next=adj[v]; adj[v]=e2;
 }
 int *used = (int*)calloc(M+1,sizeof(int));
 int *stackV = (int*)malloc((M+5)*sizeof(int));
 int *stackE = (int*)malloc((M+5)*sizeof(int));
 int top=0; // vertex stack
 int start=1; // any vertex with degree>0
 for(int i=1;i<=2*N;i++) if(adj[i]){start=i; break;}
 stackV[top++] = start;
 int *res = (int*)malloc((M+1)*sizeof(int));
 int resPos=0;
 while(top){int v = stackV[top-1];
   while(adj[v] && used[adj[v]->id]) adj[v]=adj[v]->next;
   if(adj[v]==NULL){ // backtrack
     top--;
     if(top>0){ // edge leading to this vertex is stored in stackE[top-1]
       res[resPos++] = stackE[top-1];
     }
   } else {
     Edge *e = adj[v];
     used[e->id]=1;
     stackE[top-1]=e->id;
     stackV[top++] = e->to;
   }
 }
 // output in reverse order of collection
 for(int i=resPos-1;i>=0;i--){printf("%d",res[i]); if(i) printf(" ");}
 printf("\n");
 free(adj); free(r); free(c); free(used); free(stackV); free(stackE); free(res);
 }
 return 0; }

