import java.io.*;
import java.util.*;
public class Main {
    static class Edge {int to, id; Edge(int t,int i){to=t;id=i;}}
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int M = fs.nextInt();
            int V = 2 * N + 5;
            @SuppressWarnings("unchecked")
            ArrayList<Edge>[] adj = new ArrayList[V];
            for (int i = 0; i < V; i++) adj[i] = new ArrayList<>();
            int[] r = new int[M+1];
            int[] c = new int[M+1];
            for (int i = 1; i <= M; i++) {
                r[i] = fs.nextInt();
                c[i] = fs.nextInt();
                int u = r[i];
                int v = N + c[i];
                adj[u].add(new Edge(v,i));
                adj[v].add(new Edge(u,i));
            }
            boolean[] used = new boolean[M+1];
            int start = 1;
            while (start < V && adj[start].isEmpty()) start++;
            Deque<Integer> stackV = new ArrayDeque<>();
            Deque<Integer> stackE = new ArrayDeque<>();
            List<Integer> ans = new ArrayList<>();
            stackV.push(start);
            while (!stackV.isEmpty()) {
                int v = stackV.peek();
                while (!adj[v].isEmpty() && used[adj[v].get(adj[v].size()-1).id])
                    adj[v].remove(adj[v].size()-1);
                if (adj[v].isEmpty()) {
                    stackV.pop();
                    if (!stackE.isEmpty()) {
                        ans.add(stackE.pop());
                    }
                } else {
                    Edge e = adj[v].remove(adj[v].size()-1);
                    used[e.id] = true;
                    stackE.push(e.id);
                    stackV.push(e.to);
                }
            }
            for (int i = ans.size()-1; i >= 0; i--) {
                out.append(ans.get(i));
                if (i > 0) out.append(' ');
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }
    // Fast scanner
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream is){in=is;}
        private int readByte() throws IOException {
            if (ptr >= len) { len = in.read(buffer); ptr = 0; if (len <= 0) return -1; }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') { val = val * 10 + c - '0'; c = readByte(); }
            return val * sign;
        }
    }
}

