const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
if (data.length === 0) process.exit(0);
const T = Number(data[idx++]);
let output = [];
for (let tc = 0; tc < T; tc++) {
  const N = Number(data[idx++]);
  const M = Number(data[idx++]);
  const V = 2 * N + 5;
  const adj = Array.from({ length: V }, () => []);
  const rows = new Array(M + 1);
  const cols = new Array(M + 1);
  for (let i = 1; i <= M; i++) {
    const r = Number(data[idx++]);
    const c = Number(data[idx++]);
    rows[i] = r; cols[i] = c;
    const u = r;
    const v = N + c;
    adj[u].push([v, i]);
    adj[v].push([u, i]);
  }
  const used = new Array(M + 1).fill(false);
  let start = 1;
  while (start < V && adj[start].length === 0) start++;
  const stackV = [start];
  const stackE = [];
  const ans = [];
  while (stackV.length) {
    const v = stackV[stackV.length - 1];
    while (adj[v].length && used[adj[v][adj[v].length - 1][1]]) adj[v].pop();
    if (adj[v].length === 0) {
      stackV.pop();
      if (stackE.length) ans.push(stackE.pop());
    } else {
      const [to, id] = adj[v].pop();
      used[id] = true;
      stackE.push(id);
      stackV.push(to);
    }
  }
  output.push(ans.reverse().join(' '));
}
